var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으, 으와아아!? 오지 마! 저리 가! 떨어져!","JPN":"う、うわああ！？　来るな！　あっち行け！　離れろ！","ENG":"A-aaahh!? No! Go away! Get off me!","TWN":"呃，呃啊啊啊！？別過來！走開！滾開！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"도망치는 재주 하나는 천부적이네. 그 기세로 적에게 달려들 수 있다면 좋을 텐데.","JPN":"逃げる能力だけは天才的ね。その勢いで敵に攻撃できたらいいのに。","ENG":"You really are talented at running away. It would be great if you could use that force to charge toward enemies too.","TWN":"你很有逃跑的天分呢，真希望你能一鼓作氣衝向敵人。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"농담하지 마세요…. 이런 난장판에 휘말리는 것 자체가 저에겐 엄청나게 스트레스라고요.","JPN":"冗談言わないでくださいよ……こんな修羅場に巻き込まれること自体、私にはとんでもないストレスなんですから。","ENG":"Don't joke around... Even being entangled in this mess is extremely stressful for me.","TWN":"開什麼玩笑…光是淌這個渾水，就已經讓我感到壓力山大。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그보다 아주머니는요?","JPN":"それより、おばさんは？","ENG":"But, what about Madam Schneider?","TWN":"不過有看到伯母嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"충돌이 일어났을 때 우두머리로 보이던 청년이 끌고 간 모양입니다.","JPN":"衝突が起きたとき、敵のリーダらしき青年に連れていかれたようです。","ENG":"The young man who appeared to be the head of the group seems to have dragged her away when we collided.","TWN":"剛才一陣混亂當中，似乎被領頭的年輕人帶走了。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 그 녀석은 걱정하지 마! 지금 이쪽에서 추적 중이거든!","JPN":"あ、そっちは心配しないで！　今追跡中だから！","ENG":"Ah, don't worry about him! We're tracking him right now!","TWN":"放心！我們正在追蹤那傢伙！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이동 선상에 제법 규모가 되는 시설이 있더군.","JPN":"動線上にかなり大きな施設があった。","ENG":"There was a sizable facility in the direction they were heading.","TWN":"在移動路線上發現一個頗具規模的設施。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"군사 목적으로 세워진 모양이다.","JPN":"おそらく軍事目的の施設だろう。","ENG":"It seems to have been built for military purposes.","TWN":"看起來像是因為軍事目的而建的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……기회가 있었는데도 포로로 삼았다는 건, 역시 다른 이유가 있기 때문이겠죠?","JPN":"……チャンスがあったにも関わらず人質にしたってことは、やっぱり別の目的があるんでしょうか？","ENG":"...He had the chance to kill her, but he took her captive. That must mean he has other plans, right?","TWN":"……明明可以下手將伯母殺掉，卻選擇抓她當俘虜，他們果然另有企圖嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"예를 들어…. 인질로 사용한다거나. 정부와 거래하려 한다거나.","JPN":"たとえば……人質として利用するとか、政府との取引に使うとか。","ENG":"Like... using her as hostage. Or trading with the government.","TWN":"譬如說…要抓她當人質，或是與政府進行交易？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런 악의적인 발상을 잘도 떠올리는군, 중사. 감탄스러워.","JPN":"よくもそんなに悪意に満ちた発想ができるな、軍曹。尊敬に値する。","ENG":"Seems like those evil plans just come to you naturally, Sergeant. Remarkable.","TWN":"中士，你腦中很多邪惡的想法嘛，真是佩服。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그렇죠, 뭐. 보고 자란 게 그런 것들이라서.","JPN":"まぁ、仕方がないですよ。そういうのばかり見て育ったんで。","ENG":"Well, I mean, it's what I grew up with.","TWN":"有什麼辦法？誰叫我從小就在那種環境中長大。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"좌표 보내 주세요. 다른 분들과 같이 그리로 갈게요.","JPN":"座標を送ってください。他の方々と一緒にそちらに向かいます。","ENG":"Send me the coordinates. We'll all head there together.","TWN":"把座標傳給我，我會和大家一起出發。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하아…. 상상 친구 씨, 어째서 필그림까지 끼어드는 걸까요….","JPN":"はぁ……エア友さん、どうしてピルグリムまで出てくるんでしょうか……","ENG":"*Sigh...* Now the Pilgrims, too? But why, Mr. Imaginary Friend? Why...?","TWN":"哀…我想像中的朋友，為什麼連朝聖者要來湊一腳呢…"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"꽤 의욕적으로 움직이는군요. 휴먼. 다시 봤습니다.","JPN":"かなり意欲的に動いていますね、ヒューマン。見直しました。","ENG":"You're moving with intent, human. Impressive.","TWN":"人類，沒想到你這麼積極，我對你刮目相看。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으헷!?","JPN":"うへっ！？","ENG":"Hegh?!","TWN":"哇咧？！"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"까, 깜짝이야…. 적인 줄 알았잖아요.","JPN":"び、びっくりしたぁ……敵かと思いましたよ。","ENG":"Y-you scared me... I thought you were the enemy.","TWN":"想…嚇死我…我還以為是敵人咧。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어차피 싸울 때는 다른 사람들한테 맡기고 도망다니기나 하는 걸요.","JPN":"どうせ戦闘になったら誰かに任せて逃げ回るだけですから。","ENG":"I mean, during combat, I leave it up to everyone else and just run.","TWN":"反正打起來的話，我就把別人推出去，自己快點逃。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도 호라이즌 씨가 그렇게 봐 준다니까 나쁘진 않네요.","JPN":"それでもホライズンさんがそんなふうに評価してくれるのは悪くないですね。","ENG":"Still, it's cool that you think so, Horizon.","TWN":"不過能夠得到地平線的認同還蠻開心的。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그건 어째서입니까?","JPN":"どうしてですか？","ENG":"Why is that?","TWN":"為什麼？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어째서라고 해도…. 호라이즌 씨는 샤레이드의 유명인사잖아요.","JPN":"どうしてって……ホライズンさんはシャレードの有名人じゃないですか。","ENG":"Why...? Well, you're a celebrity in Charade.","TWN":"為什麼嗎……因為地平線是查雷德的大名人嘛。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전 그런 과격한 일은 자진해서 못 저지를 걸요. 절대로.","JPN":"私には進んであんな過激なことやれません。絶対に。","ENG":"I'd never be able to do something that bold voluntarily. Never.","TWN":"換做是我，絕對做不出那麼激烈的事。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저에게는 지금 당신이 하는 행동이 더 과격하게 보입니다만.","JPN":"私には今のあなたの方がよっぽど過激に見えますが。","ENG":"I consider your current course of action bolder than my own.","TWN":"對我而言，你現在的行為比那時候的我還激烈。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런가요…?","JPN":"そうですか……？","ENG":"Really...?","TWN":"是嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"객관적으로 당신의 전력은 2종 침식체와 견줄 수준입니다.","JPN":"客観的に見て、あなたの戦闘力は第2種侵食体と同等です。","ENG":"Objectively, your strength is that of a Category 2 C.O.","TWN":"客觀來講，你的戰鬥力相當於2類侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런데도 5종 침식체를 노골적으로 적대하고 있죠.","JPN":"それなのに第5種侵食体と敵対しています。","ENG":"However, you are openly working against a Category 5 C.O.","TWN":"然而你卻公然對抗5類侵蝕體。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"직접 관련되지 않은 상태로 정보를 접했다면 자살 지망자로 분류했을 겁니다.","JPN":"直接関わっていない状態でその情報を受けたら、自殺希望者として分類していたでしょう。","ENG":"If I were to receive that information without being directly connected to it, I would have categorized you as suicidal.","TWN":"要是我今天作為一個旁觀者，一定會把你歸類為有自殺傾向。"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 하하…. 별거 아니에요. 그냥…….","JPN":"あ、はは……そんな大したことじゃないですよ。私はただ……","ENG":"Ah, ha ha... It's nothing. Just...","TWN":"哈，哈哈…不是啦，我只是……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그냥 가정사 때문이에요.","JPN":"家庭の事情ってやつです。","ENG":"It's because of my family issues.","TWN":"是因為我家裡的關係。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"애초에 저 같은 약골이 애써 봤자 뭐 얼마나 달라지겠어요?","JPN":"そもそも私みたいな弱虫が頑張ったって、何かが変わるわけないですし。","ENG":"How much could a weakling like me change the situation in the first place?","TWN":"反正像我這種弱者，再怎麼掙扎也無法改變什麼。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"호라이즌 씨처럼 강한 사람은 다르겠지만요.","JPN":"ホライズンさんのような強い人なら違うと思いますが。","ENG":"Of course, it's not the same for someone as strong as you, Horizon.","TWN":"畢竟我不像你這麼厲害。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 총사대장님이 좌표를 보내 주셨네요.","JPN":"あ、銃士隊長が座標を送ってきました。","ENG":"Ah, the General Musketeer sent us the coordinates.","TWN":"喔，射擊隊長把座標傳過來了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어서 가요, 호라이즌 씨. 필그림이 또 아주머니를 어디론가 빼돌리면 곤란해질 테니까요.","JPN":"早く行きましょう、ホライズンさん。ピルグリムにまたおばさんを隠されたら困りますからね。","ENG":"Let's go, Horizon. We can't have those Pilgrims sneak Madam Schneider away.","TWN":"快走吧，地平線。萬一朝聖者又把伯母藏起來就糟糕了。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"확실히 약골이 애쓴다고 바뀌는 건 없죠.","JPN":"確かに弱虫が頑張ったところで何かが変わることはありません。","ENG":"It is true that weaklings cannot drive change.","TWN":"弱者的掙扎確實無法改變什麼。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 아무 의미 없지는 않을 겁니다. 휴먼.","JPN":"しかし、意味がないということはありません。ヒューマン。","ENG":"However, it will not be meaningless, human.","TWN":"但這並非完全沒有意義的，人類。"},"stage":{"bg":"COUNTRYROAD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};